import json
import pymysql
import os
from typing import Dict, List, Any, Tuple

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        query_params = event.get('queryStringParameters', {}) or {}
        body_params = {}
        
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except json.JSONDecodeError:
                return {
                    'statusCode': 400,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'Invalid JSON in request body'})
                }
        
        search_params = {**query_params, **body_params}
        
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5
        )
        
        query, params = build_search_query(search_params)
        
        with connection.cursor() as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'count': len(results),
                'products': results
            }, default=str)
        }
        
    except pymysql.MySQLError as e:
        print(f"Database error: {str(e)}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': 'Database error occurred'})
        }
        
    except ValueError as e:
        print(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }
        
    except Exception as e:
        print(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': 'Internal server error'})
        }
        
    finally:
        if connection:
            connection.close()


def build_search_query(search_params: Dict[str, Any]) -> Tuple[str, List[Any]]:
    base_query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    params = []
    
    allowed_fields = {
        'name': 'string',
        'category': 'string',
        'brand': 'string',
        'sku': 'string',
        'description': 'string',
        'min_price': 'float',
        'max_price': 'float',
        'in_stock': 'boolean',
        'status': 'string',
        'tags': 'string'
    }
    
    allowed_sort_fields = ['name', 'price', 'created_at', 'updated_at', 'popularity']
    allowed_sort_orders = ['ASC', 'DESC']
    
    for field, value in search_params.items():
        if field in ['limit', 'offset', 'sort_by', 'sort_order']:
            continue
            
        if field not in allowed_fields:
            continue
        
        if value is None or value == '':
            continue
        
        field_type = allowed_fields[field]
        
        if field == 'min_price':
            try:
                price_value = float(value)
                if price_value < 0:
                    raise ValueError("min_price must be non-negative")
                conditions.append("price >= %s")
                params.append(price_value)
            except (ValueError, TypeError):
                raise ValueError(f"Invalid value for min_price: {value}")
                
        elif field == 'max_price':
            try:
                price_value = float(value)
                if price_value < 0:
                    raise ValueError("max_price must be non-negative")
                conditions.append("price <= %s")
                params.append(price_value)
            except (ValueError, TypeError):
                raise ValueError(f"Invalid value for max_price: {value}")
                
        elif field == 'in_stock':
            if str(value).lower() in ['true', '1', 'yes']:
                conditions.append("stock_quantity > 0")
            elif str(value).lower() in ['false', '0', 'no']:
                conditions.append("stock_quantity = 0")
                
        elif field in ['name', 'description', 'tags']:
            conditions.append(f"{field} LIKE %s")
            params.append(f"%{sanitize_like_pattern(str(value))}%")
            
        elif field_type == 'string':
            conditions.append(f"{field} = %s")
            params.append(str(value))
    
    if conditions:
        base_query += " AND " + " AND ".join(conditions)
    
    sort_by = search_params.get('sort_by', 'created_at')
    sort_order = search_params.get('sort_order', 'DESC').upper()
    
    if sort_by not in allowed_sort_fields:
        sort_by = 'created_at'
    
    if sort_order not in allowed_sort_orders:
        sort_order = 'DESC'
    
    base_query += f" ORDER BY {sort_by} {sort_order}"
    
    limit = search_params.get('limit', '100')
    offset = search_params.get('offset', '0')
    
    try:
        limit_value = int(limit)
        offset_value = int(offset)
        
        if limit_value < 1 or limit_value > 1000:
            limit_value = 100
        if offset_value < 0:
            offset_value = 0
            
        base_query += f" LIMIT {limit_value} OFFSET {offset_value}"
        
    except (ValueError, TypeError):
        base_query += " LIMIT 100 OFFSET 0"
    
    return base_query, params


def sanitize_like_pattern(value: str) -> str:
    return value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')